window.__QUIZ_DATA__=[{"id":"objective>Geography>2023>1","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map in Representative Fraction(RF) is","images":["data:image/png;base64,"],"options":{"A":"1:25,000","B":"1:50,000","C":"1:100,000","D":"1:200,000"},"answer":"C","explanation":"From 0 to 2 on the map scale, using a ruler it is 1cm; and the distance on the ground 1km  scale: 1cm : 1km  N.B: 1km=1000m \u2261 100,000cm  Scale = 1cm : 100,000cm or 1 : 100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>2","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the highest contour line in the mapped area?","images":["data:image/png;base64,"],"options":{"A":"600 metres","B":"500 metres","C":"400 metres","D":"300 metres"},"answer":"B","explanation":"On the map, the highest contour line is 500metres.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>3","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Stone crushing is an economic activity at","images":["data:image/png;base64,"],"options":{"A":"Agub","B":"Noyo","C":"Umughara","D":"Ameka"},"answer":"C","explanation":"Umughara, having the highest contour line is suspected to be mountainous and stone crushing is common around mountain.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>4","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which of the following towns is not intervisible from Agubia?","images":["data:image/png;base64,"],"options":{"A":"Ameka","B":"ABADA","C":"Ndifu Achara","D":"Nsuba"},"answer":"D","explanation":"Agubia and Nsuba are not intervisible because of the contour line which separates them, i.e a steep slope","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>5","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The feature marked P in the mapped area can best be described as a","images":["data:image/png;base64,"],"options":{"A":"mountain","B":"knoll","C":"valley","D":"ridge"},"answer":"D","explanation":"A ridge is a strip of highland which is elongated and narrow. The contours run almost parallel to each other","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>6","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance between Umughara and Ndifu Achara as the crow flies is approximately","images":["data:image/png;base64,"],"options":{"A":"8 km","B":"11 km","C":"18 km","D":"23 km"},"answer":"C","explanation":"To get distance:  i. Measure using a thread  ii. Compare your result with the scale","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>7","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The bearing of Ameka from Aba Omege road junction is approximately","images":["data:image/png;base64,"],"options":{"A":"22o","B":"40o","C":"90o","D":"220o"},"answer":"A","explanation":"The bearing of Ameka from Aba Omege road junction is approximately 22o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>8","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The likely occupation of the people of Ndifu Achara settlement is","images":["data:image/png;base64,"],"options":{"A":"rice farming","B":"trading","C":"gold mining","D":"lumbering"},"answer":"A","explanation":"On the map, there is presence of rice farm around Ndifu Achara","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>9","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"At what stage is River Aboye?","images":["data:image/png;base64,"],"options":{"A":"Youthful stage","B":"Mature stage","C":"Middle stage","D":"Initial stage"},"answer":"A","explanation":"River Aboye is at its youthful stage. This is due to the fact that it has a steep slope","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>10","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The area covered by the map is approximately","images":["data:image/png;base64,"],"options":{"A":"900 Km2","B":"1010 Km2","C":"1400 Km2","D":"1950 Km2"},"answer":"B","explanation":"To get the area covered:  i. Use your ruler to measure the dimensions of the map i.e length and breadth  ii. Convert your results to km using the scale asa reference  iii. Multiply the values you get in km together","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>11","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of station Z. Study and use it to answer questions 11 to 13.  station Z  MonthJan.Feb.Mar.Apr.May.Jun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)222529323128272627272623Rainfall (mm)03313641222083071401300    What is the annual range of temperature for Station Z?","images":[],"options":{"A":"10 oC","B":"22 oC","C":"32 oC","D":"54 oC"},"answer":"A","explanation":"Range = Highest temperature - Lowest temperature  Highest = 32oC  Lowest = 22oC  Range = 32oC - 22oC=10oC","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>12","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of station Z. Study and use it to answer questions 11 to 13.  station Z  MonthJan.Feb.Mar.Apr.May.Jun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)222529323128272627272623Rainfall (mm)03313641222083071401300Which month of the year has the highest temperature?","images":[],"options":{"A":"May","B":"June","C":"August","D":"April"},"answer":"D","explanation":"From the table, the month with the highest temperature is April with 32 degrees Celsius.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>13","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of station Z. Study and use it to answer questions 11 to 13.  station Z  MonthJan.Feb.Mar.Apr.May.Jun.Jul.Aug.Sep.Oct.Nov.Dec.Temperature(oC)222529323128272627272623Rainfall (mm)03313641222083071401300The wettest month of the year is","images":[],"options":{"A":"May","B":"July","C":"August","D":"September"},"answer":"C","explanation":"From the table, the month with the highest rainfall (wettest month) is August with 307mm of rainfall.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>14","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following distinguishes rotation from revolution?","images":[],"options":{"A":"The earth rotates on its axis while it revolves round the sun on an elliptical orbit","B":"Revolution causes day and night while rotation while rotation causes season","C":"A complete revolution takes 24 hours while rotation marks a year","D":"Rotation causes variation in the lengths of day and night while revolution causes rising and falling of tides"},"answer":"A","explanation":"Rotation is simply the movement of the earth on its axis. Rotation causes day and night. A complete rotation takes 24 hrs. Rotation causes rise and fall in tides.  Revolution is the movement of the earth around the sun in an elliptical orbit  Revolution causes changes in season  A complete revolution marks a year","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>15","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"The type of energy that is most environmentally friendly is","images":[],"options":{"A":"hydroelectric","B":"solar","C":"thermal","D":"nuclear"},"answer":"B","explanation":"Solar energy is considered the most environmentally friendly type of energy. This is because it is a renewable source of energy that does not emit any greenhouse gases during production. Solar panels can be installed on rooftops, which does not require any additional space. The energy production is also silent which is beneficial for urban and populated areas.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>16","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following represents the correct sequence in which denudation occurs?","images":[],"options":{"A":"Weathering \u2192 Erosion \u2192 Deposition","B":"Deposition \u2192 Weathering \u2192 Erosion","C":"Erosion \u2192 Weathering \u2192 Deposition","D":"Weathering \u2192Deposition  \u2192 Erosion"},"answer":"A","explanation":"Denudation is the process of wearing away or removing the surface of the earth. The correct sequence in which denudation occurs is: Weathering \u2192 Erosion \u2192 Deposition. Weathering is the breaking down of rocks, soil and minerals as well as wood and artificial materials through contact with the Earth's atmosphere, water, and biological organisms. Erosion is the process that breaks things down. As far as we're concerned, erosion is the breakdown of the continents and the land around you. The overall effect of breaking down and wearing away is called weathering. Deposition is the geological process in which sediments, soil and rocks are added to a landform or land mass.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>17","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following landforms is associated with parallel faulting?","images":[],"options":{"A":"Dyke","B":"Inselberg","C":"Gorge","D":"Rift valley"},"answer":"D","explanation":"A rift valley is a linear shaped lowland between several highlands or mountain ranges created by the action of a geologic rift or fault. This process of valley formation is known as parallel faulting. A rift valley is formed on a divergent plate boundary, a crustal extension, a spreading apart of the surface, which is subsequently further deepened by the forces of erosion. When the tensional forces are strong enough to cause a plate to split apart, it does so along a rift zone.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>18","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The instrument used to measure relative humidity is called","images":[],"options":{"A":"hygrometer","B":"barometer","C":"anemometer","D":"thermometer"},"answer":"A","explanation":"A hygrometer is an instrument used to measure the amount of humidity and water vapor in the atmosphere, in soil, or in confined spaces. Humidity measurement instruments usually rely on measurements of some other quantity such as temperature, pressure, mass, a mechanical or electrical change in a substance as moisture is absorbed.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>19","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The sun is vertically overhead at the tropic of Capricorn on","images":[],"options":{"A":"March 21st","B":"September 23rd","C":"December 22nd","D":"June 21st"},"answer":"C","explanation":"On December 22nd, the sun is overhead at the Tropic of capricon, resulting in December winter solstice","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>20","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following pairs of landforms can be found in the desert areas?","images":[],"options":{"A":"Yardangs and batholiths","B":"Sandbars and tombolos","C":"Zeugens and rock pedestals","D":"Barchans and tombolos"},"answer":"C","explanation":"Zeugens and rock pedestals are landforms that can be found in desert areas. Zeugens are formed by wind erosion and are characterized by a ridge and furrow landscape. Rock pedestals are also formed by wind erosion, where a rock formation is reduced to a column because the lower parts have been more heavily eroded than the upper parts.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>21","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The part of the earth crust covered by water bodies is known as the","images":[],"options":{"A":"sial","B":"stratosphere","C":"hydrosphere","D":"atmosphere"},"answer":"C","explanation":"The part of the earth's crust covered by water bodies is known as the hydrosphere. The hydrosphere includes all water bodies on the earth's surface such as oceans, seas, lakes, rivers, and even underground water.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>22","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance between town A located on latitude 30o S and town B located on latitude 30o N is","images":[],"options":{"A":"3330 km","B":"6660 km","C":"9000 km","D":"9770 km"},"answer":"B","explanation":"town B (30oN) town A (30oS)  latitude difference = 30 + 30 (Different Latitude add)= 60o  But, 1o=111km  60o = x cross multiply  x=60 x 111=6660","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>23","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"What is the temperature around an aeroplane flying at an altitude of 4000 metres if the temperature on the earth surface is 40 oC?","images":[],"options":{"A":"12 oC","B":"14 oC","C":"26 oC","D":"66 oC"},"answer":"B","explanation":"Initial temperature = 40oC  Final temperature = ?  According to lapse rate  1000m ascent = 6.5oC decrease in temp.  4000m =x  4000 = 6.5 x 4=26.0oC  Final temp. = (40o -26o)C=14oC","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>24","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"A block mountain is formed as a result of","images":[],"options":{"A":"differential erosion","B":"vulcanicity","C":"faulting","D":"fissure"},"answer":"C","explanation":"Block mountains are formed as a result of faulting. Faulting is a geological process where the Earth's crust breaks apart due to tectonic forces. This can result in large blocks of land being uplifted to form mountains.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>25","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Volcanoes that have not erupted for a very long time but may erupt at future time are termed as","images":[],"options":{"A":"dormant","B":"active","C":"extrusive","D":"intrusive"},"answer":"A","explanation":"Volcanoes that have not erupted for a very long time but may erupt at future time are termed as dormant","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>26","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Barchan dunes move","images":[],"options":{"A":"in the same direction as the prevailing winds","B":"against the prevailing wind","C":"at right angle to the prevailing wind","D":"in a circular direction"},"answer":"C","explanation":"Barchan dunes move at right angle to the prevailing wind.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>27","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following rocks is produced by the solidification of magma within the earth crust?","images":[],"options":{"A":"Metamorphic rock","B":"Sedimentary rock","C":"Extrusive rock","D":"Plutonic rock"},"answer":"D","explanation":"Plutonic Igneous rocks also known as intrusive igneous rocks are formed when the molten magma cools and solidifies slowly before it gets to the surface of the earth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>28","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Town C is located on latitude 15oE while Town D is located on latitude 60oE. If the local time in Town C is 7.00am., what will be the local time in Town D?","images":[],"options":{"A":"4.00 p.m","B":"4.00 a.m","C":"10.00 p.m","D":"10.00 a.m"},"answer":"D","explanation":"Town C(15oE) Town D(60oE)  7:00am ---add---> x  Note: 15oE comes first 60oE  longitude difference  (60-15) same longitude youn substract  45o  convet 45o to time  15o \u2192 1hr  45o \u2192 3hrs  \u2234 Time at town D =  + + 3 = 10:00am","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>29","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Under the Greek system of climate classification, the world is divided into","images":[],"options":{"A":"hot, temperate and dry zones","B":"torrid, equatorial and tropical zones","C":"temperate, frigid and hot zones","D":"torrid, temperate and frigid zones"},"answer":"D","explanation":"The Greek system of climate classification divides the world into; torrid, temperate and frigid zones","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>30","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"An isotherm is a line drawn on a map joining places of equal","images":[],"options":{"A":"cloud cover","B":"pressure","C":"rainfall","D":"temperature"},"answer":"D","explanation":"An isotherm is a line on a map or chart of the earth's surface connecting points having the same temperature at a given time or the same mean temperature for a given period. Therefore, it joins places of equal temperature.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>31","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is a wind deposited landforms?","images":[],"options":{"A":"Loess","B":"Rock pedestal","C":"Deflation hollow","D":"Yardang"},"answer":"A","explanation":"Loess is a wind-deposited sediment that is composed of fine particles of dust, clay and silt. It is a landform created by the action of wind. Other options like Rock pedestal, Deflation hollow, Yardang are formed by the action of water and erosion, not wind.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>32","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"When weathering occurs on hillslopes, rock debris usually pile up at the bottom of the hill slope to form","images":[],"options":{"A":"creep","B":"pebbles","C":"screes","D":"levee"},"answer":"C","explanation":"When weathering occurs on hillslopes, the rock debris usually pile up at the bottom of the hill slope to form 'screes'. A scree is a collection of broken rock fragments at the base of crags, mountain cliffs, volcanoes or valley shoulders that has accumulated through periodic rockfall from adjacent cliff faces.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>33","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A smaller range of temperature is recorded along the coast than the continental interior on the same latitudes because of the","images":[],"options":{"A":"higher insolation inland","B":"higher evaporation inland","C":"moderating influence of the sea","D":"thicker vegetation on the coast"},"answer":"C","explanation":"The moderating influence of the sea is the reason why a smaller range of temperature is recorded along the coast than the continental interior on the same latitudes. This is because water has a higher specific heat capacity than land, meaning it can absorb and release heat more slowly than land. This results in cooler summers and warmer winters along the coast, leading to a smaller temperature range.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>34","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is an important line of longitude?","images":[],"options":{"A":"Tropic of Cancer","B":"Antarctic Circle","C":"Arctic Circle","D":"Prime Meridian"},"answer":"D","explanation":"The Prime Meridian is an important line of longitude. It is the line of 0 degree longitude, from which all other longitudes are calculated. It passes through Greenwich, London, and is used as the standard for the world time zone system.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>35","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following features is associated with the upper course of a river?","images":[],"options":{"A":"Waterfall","B":"Meander","C":"Delta","D":"Levee"},"answer":"A","explanation":"Waterfall is a feature of the upper course of a river. It has a steep slope which forms plunge pools.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>36","subject":"Geography","year":"2023","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a process of chemical weathering?","images":[],"options":{"A":"Carbonation","B":"Hydrolysis","C":"Oxidation","D":"Frost action"},"answer":"D","explanation":"Chemical weathering involves the process of rock decomposition due to chemical reactions. The processes include carbonation, hydrolysis, and oxidation. Frost action, on the other hand, is a form of physical weathering where water seeps into cracks in rocks, freezes, and expands, causing the rock to break apart. Therefore, frost action is not a process of chemical weathering.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>37","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Which of the following factors is a major boost to tourism?","images":[],"options":{"A":"Adequate publicity about natural scenery","B":"Higher dependency ratio of the population","C":"Specialization in labour force","D":"Variation in mode of transportation"},"answer":"A","explanation":"Tourism is significantly boosted by adequate publicity about natural scenery. This is because it attracts tourists who are interested in exploring and experiencing the beauty of nature. The other options such as higher dependency ratio of the population, specialization in labour force, and variation in mode of transportation do not directly boost tourism.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>38","subject":"Geography","year":"2023","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following is not a plantation crop?","images":[],"options":{"A":"Rubber","B":"Oil palm","C":"Cocoa","D":"Rye"},"answer":"D","explanation":"Plantation crops are typically tropical crops that are grown on a large scale in plantations. These include rubber, oil palm, and cocoa. Rye, on the other hand, is a cereal grain that's not typically grown on plantations, making it not a plantation crop.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>39","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The sparse population in the middle belt of West Africa can be traced to all the following except","images":[],"options":{"A":"inter-ethnic war","B":"Arab slave trade in the north","C":"tsetse fly infestation","D":"concentration of industries"},"answer":"D","explanation":"The sparse population in the middle belt of West Africa can be traced to all the following except concentration of industries","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>40","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The main reason for which most manufacturing industries in West Africa are concentrated in cities and towns along the coast is that they have","images":[],"options":{"A":"a large pool of unskilled labour","B":"large urban market","C":"numerous banks","D":"a large number of warehouses"},"answer":"B","explanation":"The main reason for which most manufacturing industries in West Africa are concentrated in cities and towns along the coast is that they have large urban market","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>41","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The most common form of migration experienced in countries of Tropical Africa is","images":[],"options":{"A":"urban-urban migration","B":"rural-rural migration","C":"urban-rural migration","D":"rural-urban migration"},"answer":"D","explanation":"Countries of Tropical Africa  usually experience rural-urban migration i.e [movement from rural to urban settlement]","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>42","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Great Britain and Germany are trading partners of West African countries from","images":[],"options":{"A":"West Europe","B":"North America","C":"South America","D":"The Far East"},"answer":"A","explanation":"Great Britain and Germany belong to the europian continent. To be more precise they belong to the Western part of Europe.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>43","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is a feature of heavy industries?","images":[],"options":{"A":"Small scale plants","B":"Capital intensive","C":"Low turn-over","D":"Consumer goods production"},"answer":"B","explanation":"Heavy industries are characterized by their large-scale operations and high capital investment. They are capital intensive.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>44","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following criteria is used to classify settlements into rural or urban?","images":[],"options":{"A":"Age","B":"Site","C":"Function","D":"Location"},"answer":"C","explanation":"The major criteria used to classify settlements into rural or urban is based on the functions which they perform.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>45","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"What is the population density of a country with a total population of 140,000,000 and a total land area of 500,000 km2?","images":[],"options":{"A":"200 persons per km2","B":"280 persons per km2","C":"350 persons per km2","D":"500 persons per km2"},"answer":"B","explanation":"The population density of a country is calculated by dividing the total population by the total land area. Therefore, for a country with a total population of 140,000,000 and a total land area of 500,000 km2, the population density would be 140,000,000 / 500,000 = 280 persons per km2.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>46","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following is not a problem facing transportation development in Tropical Africa?","images":[],"options":{"A":"Difficult terrain","B":"Inadequate capital","C":"Poor planning","D":"Climatic variation"},"answer":"D","explanation":"All the options listed are problems facing transportation development in Tropical Africa except for 'Climatic variation'. While climatic variation can affect transportation, it is not a major problem facing its development in Tropical Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>47","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Industries are broadly classified into","images":[],"options":{"A":"primary, secondary and tertiary","B":"fishing, mining and food processing","C":"primary, secondary and manufacturing","D":"mining, furniture making and cocoa processing"},"answer":"A","explanation":"Industries are broadly classified into primary, secondary and tertiary. The primary sector involves the extraction of raw materials, the secondary sector involves the manufacturing of goods, and the tertiary sector involves the provision of services.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>48","subject":"Geography","year":"2023","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"More Hydroelectric Power projects should be constructed in Tropical Africa because","images":[],"options":{"A":"there are absence of waterfalls on rivers","B":"skilled labour is scarce","C":"there is scanty rainfall","D":"there is an increasing demand for power"},"answer":"D","explanation":"More Hydroelectric Power projects should be constructed in Tropical Africa because there is an increasing demand for power.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2023>49","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Buying and selling of goods and services within a country is termed as","images":[],"options":{"A":"international trade","B":"internal trade","C":"barter trade","D":"foreign trade"},"answer":"B","explanation":"The buying and selling of goods and services within a country is termed as 'internal trade'. This is because it involves transactions that are carried out within the geographical boundaries of a country. International trade, on the other hand, involves transactions between different countries. Barter trade is a system of exchange where goods or services are directly exchanged for other goods or services without using a medium of exchange, such as money. Foreign trade is a broader term that includes both imports and exports.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2023>50","subject":"Geography","year":"2023","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A major function performed by rural settlement is","images":[],"options":{"A":"industrial","B":"administrative","C":"agricultural","D":"commercial"},"answer":"C","explanation":"The major functions performed by rural settlements are; agricultural function, lumbering function, fishing function etc.","marks":"1","difficulty":"1"}];